import threading
import time
import random

class ATMController:
    def __init__(self, num_atms):
        self.num_atms = num_atms
        self.balances = [1000] * num_atms
        self.locks = [threading.Lock() for _ in range(num_atms)]
        self.transaction_log = []

    def deposit(self, atm_id, amount):
        with self.locks[atm_id]:
            if amount <= 0:
                return False
            self.balances[atm_id] += amount
            self.transaction_log.append((atm_id, 'deposit', amount))
            return True

    def withdraw(self, atm_id, amount):
        with self.locks[atm_id]:
            if amount <= 0 or amount > self.balances[atm_id]:
                return False
            self.balances[atm_id] -= amount
            self.transaction_log.append((atm_id, 'withdraw', amount))
            return True

    def transfer(self, from_atm, to_atm, amount):
        with self.locks[from_atm], self.locks[to_atm]:
            if amount <= 0 or amount > self.balances[from_atm]:
                return False
            self.balances[from_atm] -= amount
            self.balances[to_atm] += amount
            self.transaction_log.append((from_atm, 'transfer_out', amount))
            self.transaction_log.append((to_atm, 'transfer_in', amount))
            return True

    def audit(self):
        return self.transaction_log

    def simulate_fraud(self, atm_id, amount):
        with self.locks[atm_id]:
            if amount <= 0 or amount > self.balances[atm_id]:
                return False
            self.balances[atm_id] -= amount
            self.transaction_log.append((atm_id, 'fraud', amount))
            return True

